class Solution {
    /**
     * @param {number[]} nums Array of integers
     * @param {number} target Target sum to find
     * @return {number[]} Indices of the two numbers that add up to target
     */
    twoSum(nums, target) {
        const hm = new Map();

        for (let i = 0; i < nums.length; i++) {
            const n = nums[i];
            const diff = target - n;
            if (hm.has(diff)) {
                return [hm.get(diff), i];
            }
            hm.set(n, i);
        }
        return [];
    }
}

