class Solution {
    public boolean isAnagram(String s, String t) {
        // Check lengths first
        if (s.length() != t.length()) {
            return false;
        }

        int[] count = new int[26];
        for (int i = 0; i < s.length(); i++) {
            count[s.charAt(i) - 'a']++;
            count[t.charAt(i) - 'a']--;
        }

        // Verify character frequencies match
        for (int value : count) {
            if (value != 0) {
                return false;
            }
        }
        return true;
    }
}

