    def maxProfit(self, prices: List[int]) -> int:
        # Initialize result and left pointer (buying position)
        res = l = 0

        # Iterate through prices with right pointer (selling position)
        for r in range(len(prices)):
            # Update maximum profit if we can get better profit
            res = max(res, prices[r] - prices[l])
            # If we find a lower buying price, update left pointer
            if prices[r] < prices[l]:
                l = r

        return res

