class Solution {
public:
    int maxProfit(vector<int>\u0026 prices) {
        // Edge case: if array is empty or has only one element, no profit possible
        if (prices.size() <= 1) return 0;

        int minPrice = prices[0];  // Track minimum price seen so far
        int maxProfit = 0;         // Track maximum profit possible

        // Iterate through prices starting from second element
        for (int i = 1; i < prices.size(); i++) {
            // Update minimum price if current price is lower
            minPrice = min(minPrice, prices[i]);
            // Update maximum profit if selling at current price yields higher profit
            maxProfit = max(maxProfit, prices[i] - minPrice);
        }

        return maxProfit;
    }
};

