class MyHashMap {
private:
    static const int SIZE = 1009;
    vector<vector<pair<int,int>>> buckets;

    int _hash(int key) {
        return key % SIZE;
    }

public:
    MyHashMap() {
        buckets.resize(SIZE);
    }

    void put(int key, int value) {
        int h = _hash(key);
        for (auto\u0026 p : buckets[h]) {
            if (p.first == key) {
                p.second = value;
                return;
            }
        }
        buckets[h].push_back({key, value});
    }

    int get(int key) {
        int h = _hash(key);
        for (auto\u0026 p : buckets[h]) {
            if (p.first == key) {
                return p.second;
            }
        }
        return -1;
    }

    void remove(int key) {
        int h = _hash(key);
        auto\u0026 bucket = buckets[h];
        for (auto it = bucket.begin(); it != bucket.end(); ++it) {
            if (it->first == key) {
                bucket.erase(it);
                return;
            }
        }
    }
};

