class Solution:
    def isIsomorphic(self, s: str, t: str) -> bool:
        # Two maps to ensure bijective mapping
        map_s_to_t = {}
        map_t_to_s = {}

        for c_s, c_t in zip(s, t):
            # Check s -> t mapping
            if c_s in map_s_to_t:
                if map_s_to_t[c_s] != c_t:
                    return False
            else:
                map_s_to_t[c_s] = c_t

            # Check t -> s mapping
            if c_t in map_t_to_s:
                if map_t_to_s[c_t] != c_s:
                    return False
            else:
                map_t_to_s[c_t] = c_s

        return True

