    mapTtoS := make(map[byte]byte)

    for i := 0; i < len(s); i++ {
        cS := s[i]
        cT := t[i]

        // Check s -> t mapping
        if mapped, ok := mapStoT[cS]; ok {
            if mapped != cT {
                return false
            }
        } else {
            mapStoT[cS] = cT
        }

        // Check t -> s mapping
        if mapped, ok := mapTtoS[cT]; ok {
            if mapped != cS {
                return false
            }
        } else {
            mapTtoS[cT] = cS
        }
    }

    return true
}

