    public boolean containsNearbyDuplicate(int[] nums, int k) {
        // Use a sliding window with a hash set
        // Maintain a window of size at most k
        HashSet<Integer> window = new HashSet<Integer>();
        for (int i = 0; i < nums.length; i++) {
            // If the current number is already in the window, we found a duplicate within distance k
            if (window.contains(nums[i])) {
                return true;
            }
            // Add the current number to the window
            window.add(nums[i]);
            // If the window exceeds size k, remove the oldest element
            if (window.size() > k) {
                window.remove(nums[i - k]);
            }
        }
        return false;
    }
}

