    // Initialize flags to track if array is monotone increasing or decreasing
    increasing := true
    decreasing := true

    // Compare adjacent elements
    for i := 1; i < len(nums); i++ {
        // If current element is greater than previous, array is not decreasing
        if nums[i] > nums[i-1] {
            decreasing = false
        }
        // If current element is less than previous, array is not increasing
        if nums[i] < nums[i-1] {
            increasing = false
        }
        // If array is neither increasing nor decreasing, return false
        if !increasing \u0026\u0026 !decreasing {
            return false
        }
    }

    // Return true if array is either increasing or decreasing
    return increasing || decreasing
}

