class Solution {
    /**
     * @param {string} s
     * @return {number}
     */
    countBinarySubstrings(s) {
        // prev tracks the size of the previous group of consecutive chars
        // curr tracks the size of the current group of consecutive chars
        // ans accumulates the count of valid substrings
        let prev = 0;
        let curr = 1;
        let ans = 0;

        for (let i = 1; i < s.length; i++) {
            if (s[i] === s[i - 1]) {
                curr++;
            } else {
                ans += Math.min(prev, curr);
                prev = curr;
                curr = 1;
            }
        }

        // Don't forget the last pair of groups
        ans += Math.min(prev, curr);

        return ans;
    }
}

