class Solution {
    /**
     * @param {string[]} words Array of strings
     * @param {number} k Number of frequent words to return
     * @return {string[]} k most frequent strings sorted by frequency and lexicographically
     */
    topKFrequent(words, k) {
        // Create a map to store word frequencies
        const freqMap = new Map();
        for (const word of words) {
            freqMap.set(word, (freqMap.get(word) || 0) + 1);
        }

        // Convert map entries to array and sort by frequency and lexicographically
        const sortedWords = Array.from(freqMap.entries()).sort((a, b) => {
            if (a[1] !== b[1]) {
                return b[1] - a[1]; // Sort by frequency in descending order
            }
            return a[0].localeCompare(b[0]); // Sort lexicographically for same frequency
        });

        // Return top k words
        return sortedWords.slice(0, k).map(entry => entry[0]);
    }
}

