func topKFrequent(words []string, k int) []string {
    // Create a map to count frequency of each word
    freq := make(map[string]int)
    for _, word := range words {
        freq[word]++
    }

    // Create a slice of unique words
    uniqueWords := make([]string, 0, len(freq))
    for word := range freq {
        uniqueWords = append(uniqueWords, word)
    }

    // Sort words based on frequency and lexicographical order
    sort.Slice(uniqueWords, func(i, j int) bool {
        if freq[uniqueWords[i]] == freq[uniqueWords[j]] {
            return uniqueWords[i] < uniqueWords[j]
        }
        return freq[uniqueWords[i]] > freq[uniqueWords[j]]
    })

    // Return top k frequent words
    return uniqueWords[:k]
}

