class Solution {
    public int subarraySum(int[] nums, int k) {
        // Initialize variables to track count and current sum
        int count = 0;
        int currSum = 0;

        // HashMap to store prefix sums and their frequencies
        Map<Integer, Integer> prefixSums = new HashMap<>();
        prefixSums.put(0, 1);  // Initialize with 0 sum having frequency 1

        // Iterate through the array
        for (int num : nums) {
            // Update current sum
            currSum += num;

            // If (currSum - k) exists in prefixSums, add its frequency to count
            if (prefixSums.containsKey(currSum - k)) {
                count += prefixSums.get(currSum - k);
            }

            // Update the frequency of current sum
            prefixSums.put(currSum, prefixSums.getOrDefault(currSum, 0) + 1);
        }

        return count;
    }
}

