class Solution:
    def encode(self, strs: List[str]) -> str:
        # Encode each string with its length followed by delimiter
        encoded_strs = []
        for s in strs:
            encoded_strs.append(str(len(s)) + '#' + s)
        return '|'.join(encoded_strs)

    def decode(self, s: str) -> List[str]:
        # Parse length and extract strings based on encoded format
        decoded_strs = []
        i = 0
        while i < len(s):
            if s[i] == '|':
                i += 1
                continue
            j = i
            while s[j] != '#':
                j += 1
            length = int(s[i:j])
            j += 1
            decoded_strs.append(s[j:j+length])
            i = j + length
        return decoded_strs

