class Solution {
    encode(strs) {
        // Encode array of strings into a single string with length prefix
        return strs.map(str => str.length + '#' + str).join(''|'');
    }
    decode(s) {
        // Decode the string back into an array of strings by parsing length prefixes
        const decoded_strs = [];
        let i = 0;
        while (i < s.length) {
            if (s[i] === ''|'') {
                i++;
                continue;
            }
            let j = i;
            while (s[j] !== '#') {
                j++;
            }
            const length = parseInt(s.slice(i, j));
            j++;
            decoded_strs.push(s.slice(j, j + length));
            i = j + length;
        }
        return decoded_strs;
    }
}

