func spiralOrder(matrix [][]int) []int {
    if matrix == nil || len(matrix) == 0 {
        return []int{}
    }
    result := make([]int, 0)
    top, bottom, left, right := 0, len(matrix) - 1, 0, len(matrix[0]) - 1
    // Traverse matrix in spiral order using boundaries
    for top <= bottom \u0026\u0026 left <= right {
        for i := left; i <= right; i++ {
            result = append(result, matrix[top][i])  // Right
        }
        top++
        if top > bottom { break }
        for i := top; i <= bottom; i++ {
            result = append(result, matrix[i][right])  // Down
        }
        right--
        if left > right { break }
        for i := right; i >= left; i-- {
            result = append(result, matrix[bottom][i])  // Left
        }
        bottom--
        if top > bottom { break }
        for i := bottom; i >= top; i-- {
            result = append(result, matrix[i][left])  // Up
        }
        left++
    }
    return result
}

