func isAlienSorted(words []string, order string) bool {
    // Create character to index mapping
    charMap := make(map[byte]int)
    for i := 0; i < len(order); i++ {
        charMap[order[i]] = i
    }

    // Compare adjacent words
    for i := 0; i < len(words)-1; i++ {
        word1, word2 := words[i], words[i+1]

        // Compare characters
        for j := 0; j < len(word1); j++ {
            // If word2 is shorter and all previous chars were equal
            if j >= len(word2) {
                return false
            }

            if word1[j] != word2[j] {
                // If characters differ, check if they're in correct order
                if charMap[word1[j]] > charMap[word2[j]] {
                    return false
                }
                // If they're in correct order, move to next pair of words
                break
            }
        }
    }

    return true
}

