func threeSum(nums []int) [][]int {
    sort.Ints(nums)
    triplets := [][]int{}

    for i := 0; i < len(nums)-2; i++ {
        if i > 0 \u0026\u0026 nums[i] == nums[i-1] {
            continue // Skip duplicate values for the fixed element
        }
        left, right := i+1, len(nums)-1

        for left < right {
            total := nums[i] + nums[left] + nums[right]

            if total == 0 {
                triplets = append(triplets, []int{nums[i], nums[left], nums[right]})
                for left < right \u0026\u0026 nums[left] == nums[left+1] {
                    left++ // Skip duplicate values for the left element
                }
                for left < right \u0026\u0026 nums[right] == nums[right-1] {
                    right-- // Skip duplicate values for the right element
                }
                left++
                right--
            } else if total < 0 {
                left++
            } else {
                right--
            }
        }
    }

    return triplets
}

