class Solution {
    public int characterReplacement(String s, int k) {
        // Array to store frequency of each character
        int[] charCount = new int[26];
        // Track maximum frequency in current window
        int maxFreq = 0;
        // Left pointer for sliding window
        int left = 0;
        // Track maximum valid substring length
        int maxLength = 0;

        for (int right = 0; right < s.length(); right++) {
            // Add new character to window
            charCount[s.charAt(right) - 'A']++;
            maxFreq = Math.max(maxFreq, charCount[s.charAt(right) - 'A']);

            // Shrink window if too many replacements needed
            if (right - left + 1 - maxFreq > k) {
                charCount[s.charAt(left) - 'A']--;
                left++;
            }

            maxLength = Math.max(maxLength, right - left + 1);
        }

        return maxLength;
    }
}

