class Solution:
    def firstMissingPositive(self, nums: List[int]) -> int:
        # Cyclic sort: place each number at its correct index
        # Value i should be at index i-1
        n = len(nums)

        for i in range(n):
            # Keep swapping until current element is in correct position
            # or is out of range
            while 1 <= nums[i] <= n and nums[nums[i] - 1] != nums[i]:
                # Swap nums[i] to its correct position
                correct_idx = nums[i] - 1
                nums[i], nums[correct_idx] = nums[correct_idx], nums[i]

        # Find the first index where nums[i] != i + 1
        for i in range(n):
            if nums[i] != i + 1:
                return i + 1

        # All positions 1..n are filled correctly
        return n + 1

