            # Calculate total hours needed at speed mid
            hours = 0
            for p in piles:
                hours += (p + mid - 1) // mid  # ceil(p / mid)

            if hours <= h:
                # mid is feasible, try smaller speed
                hi = mid
            else:
                # mid is too slow, need faster speed
                lo = mid + 1

        return lo

