func aggressiveCows(stalls []int, k int) int {
    // Sort stall positions
    sort.Ints(stalls)

    // Helper function to check if we can place k cows with at least minDist between each pair
    canPlace := func(minDist int) bool {
        count := 1
        lastPos := stalls[0]
        for i := 1; i < len(stalls); i++ {
            if stalls[i]-lastPos >= minDist {
                count++
                lastPos = stalls[i]
                if count >= k {
                    return true
                }
            }
        }
        return false
    }

    // Binary search on the answer
    lo := 1
    hi := stalls[len(stalls)-1] - stalls[0]
    result := 0
    for lo <= hi {
        mid := (lo + hi) / 2
        if canPlace(mid) {
            result = mid
            lo = mid + 1
        } else {
            hi = mid - 1
        }
    }

    return result
}

