    bool hasCycle(ListNode *head) {
        // Use two pointers: slow and fast
        if (!head || !head->next) {
            return false;
        }

        ListNode* slow = head;
        ListNode* fast = head->next;

        // Fast pointer moves twice as fast
        while (slow != fast) {
            if (!fast || !fast->next) {
                return false;
            }
            slow = slow->next;
            fast = fast->next->next;
        }

        return true;
    }
};

