func compress(chars []byte) []byte {
    // Two-pointer approach: read pointer scans groups, write pointer writes compressed result
    write := 0
    read := 0
    n := len(chars)

    for read < n {
        char := chars[read]
        count := 0

        // Count consecutive identical characters
        for read < n \u0026\u0026 chars[read] == char {
            read++
            count++
        }

        // Write the character
        chars[write] = char
        write++

        // Write the count if greater than 1
        if count > 1 {
            countStr := strconv.Itoa(count)
            for i := 0; i < len(countStr); i++ {
                chars[write] = countStr[i]
                write++
            }
        }
    }

    // Return the modified array truncated to the compressed length
    return chars[:write]
}

