class Solution {
    public int longestOnes(int[] nums, int k) {
        // Use sliding window approach to find longest sequence
        int left = 0;
        int maxOnes = 0;
        int zeroCount = 0;

        // Iterate through array with right pointer
        for (int right = 0; right < nums.length; right++) {
            // Count zeros in current window
            if (nums[right] == 0) {
                zeroCount++;
            }

            // Shrink window if too many zeros
            while (zeroCount > k) {
                if (nums[left] == 0) {
                    zeroCount--;
                }
                left++;
            }

            // Update maximum length
            maxOnes = Math.max(maxOnes, right - left + 1);
        }

        return maxOnes;
    }
}

