func carFleet(target int, position []int, speed []int) int {
    n := len(position)
    if n == 0 {
        return 0
    }

    // Create pairs of (position, speed) and sort by position descending
    type car struct {
        pos int
        spd int
    }
    cars := make([]car, n)
    for i := 0; i < n; i++ {
        cars[i] = car{position[i], speed[i]}
    }
    sort.Slice(cars, func(i, j int) bool {
        return cars[i].pos > cars[j].pos
    })

    // Stack to track fleet arrival times
    stack := []float64{}

    for _, c := range cars {
        // Time for this car to reach target
        time := float64(target-c.pos) / float64(c.spd)

        // If this car takes longer than the fleet ahead, it forms a new fleet
        if len(stack) == 0 || time > stack[len(stack)-1] {
            stack = append(stack, time)
        }
        // Otherwise it merges into the fleet ahead (do nothing)
    }

    return len(stack)
}

