class Solution {
    public int carFleet(int target, int[] position, int[] speed) {
        int n = position.length;
        // Create array of indices and sort by position descending
        Integer[] indices = new Integer[n];
        for (int i = 0; i < n; i++) {
            indices[i] = i;
        }
        Arrays.sort(indices, (a, b) -> position[b] - position[a]);

        // Stack to track fleet arrival times
        int fleets = 0;
        double lastTime = 0;

        for (int i = 0; i < n; i++) {
            int idx = indices[i];
            double time = (double)(target - position[idx]) / speed[idx];
            // If this car takes longer than the fleet ahead, it forms a new fleet
            if (time > lastTime) {
                fleets++;
                lastTime = time;
            }
            // Otherwise it merges into the fleet ahead
        }

        return fleets;
    }
}

