            double time = (double)(target - pairs[i].first) / pairs[i].second;
            // If this car takes longer than the fleet ahead, it forms a new fleet
            if (stack.empty() || time > stack.back()) {
                stack.push_back(time);
            }
            // Otherwise it merges into the fleet ahead (do nothing)
        }

        return (int)stack.size();
    }
};

