class Solution:
    def asteroidCollision(self, asteroids: List[int]) -> List[int]:
        # Use a stack to simulate collisions
        stack = []

        for asteroid in asteroids:
            alive = True
            # Collision happens when current asteroid moves left (negative)
            # and top of stack moves right (positive)
            while alive and asteroid < 0 and stack and stack[-1] > 0:
                # Compare sizes
                if stack[-1] < -asteroid:
                    # Top of stack is smaller, it explodes
                    stack.pop()
                elif stack[-1] == -asteroid:
                    # Both are same size, both explode
                    stack.pop()
                    alive = False
                else:
                    # Top of stack is larger, current asteroid explodes
                    alive = False

            if alive:
                stack.append(asteroid)

        return stack

