class Solution {
    /**
     * @param {string} path Unix-style file path
     * @return {string} Simplified canonical path
     */
    simplifyPath(path) {
        // Split path by '/' and filter out empty strings and single dots
        const parts = path.split('/').filter(part => part !== '' \u0026\u0026 part !== '.');
        const stack = [];

        // Process each part of the path
        for (const part of parts) {
            if (part === '..') {
                // Go up one directory if possible
                if (stack.length > 0) {
                    stack.pop();
                }
            } else {
                // Add directory to stack
                stack.push(part);
            }
        }

        // Construct canonical path
        return '/' + stack.join('/');
    }
}

