class Solution {
    /**
     * @param {number} n - Number of functions
     * @param {string[]} logs - Array of function execution logs
     * @return {number[]} - Array of exclusive execution times for each function
     */
    exclusiveTime(n, logs) {
        const stack = [];
        const result = new Array(n).fill(0);
        let prevTime = 0;

        for (const log of logs) {
            const [funcId, action, timestamp] = log.split(':');
            const id = parseInt(funcId);
            const time = parseInt(timestamp);

            if (action === 'start') {
                if (stack.length > 0) {
                    result[stack[stack.length - 1]] += time - prevTime;
                }
                stack.push(id);
                prevTime = time;
            } else { // end
                result[stack.pop()] += time - prevTime + 1;
                prevTime = time + 1;
            }
        }

        return result;
    }
}

