     * @return {ListNode}
     */
    mergeTwoLists(l1, l2) {
        // Dummy node simplifies head handling
        const dummy = new ListNode();
        let merged = dummy;

        // Compare and merge while both lists have nodes
        while (l1 \u0026\u0026 l2) {
            if (l1.val < l2.val) {
                merged.next = l1;
                l1 = l1.next;
            } else {
                merged.next = l2;
                l2 = l2.next;
            }
            merged = merged.next;
        }

        // Append remaining nodes
        merged.next = l1 || l2;

        return dummy.next;
    }
}

