func reorderList(head *ListNode) {
    if head == nil || head.Next == nil {
        return
    }

    // Step 1: Find middle with slow and fast pointers
    slow, fast := head, head
    for fast != nil \u0026\u0026 fast.Next != nil {
        slow = slow.Next
        fast = fast.Next.Next
    }

    // Step 2: Reverse second half
    var prev *ListNode
    curr := slow
    for curr != nil {
        nextNode := curr.Next
        curr.Next = prev
        prev = curr
        curr = nextNode
    }

    // Step 3: Merge halves alternately
    first, second := head, prev
    for second.Next != nil {
        nextFirst := first.Next
        nextSecond := second.Next
        first.Next = second
        second.Next = nextFirst
        first = nextFirst
        second = nextSecond
    }
}

