class Solution {
public:
    ListNode* reverseKGroup(ListNode* head, int k) {
        // Check if we have enough nodes to reverse
        if (!head || k == 1) return head;

        ListNode* check = head;
        int count = 0;
        while (check \u0026\u0026 count < k) {
            check = check->next;
            count++;
        }
        if (count < k) return head;

        // Reverse k nodes
        ListNode* curr = head;
        ListNode* prev = nullptr;
        ListNode* next_node = nullptr;
        count = 0;

        while (curr \u0026\u0026 count < k) {
            next_node = curr->next;
            curr->next = prev;
            prev = curr;
            curr = next_node;
            count++;
        }

        // Connect with the rest of the list (recursively)
        if (next_node) {
            head->next = reverseKGroup(next_node, k);
        }

        return prev;
    }
};

