func reverseKGroup(head *ListNode, k int) *ListNode {
    // Check if we have enough nodes to reverse
    hasKNodes := func(node *ListNode, k int) bool {
        count := 0
        for node != nil \u0026\u0026 count < k {
            node = node.Next
            count++
        }
        return count == k
    }

    // Base cases
    if head == nil || k == 1 {
        return head
    }

    // Check if we have k nodes to reverse
    if !hasKNodes(head, k) {
        return head
    }

    // Reverse k nodes
    curr := head
    var prev *ListNode
    var nextNode *ListNode
    count := 0

    for curr != nil \u0026\u0026 count < k {
        nextNode = curr.Next
        curr.Next = prev
        prev = curr
        curr = nextNode
        count++
    }

    // Connect with the rest of the list
    if nextNode != nil {
        head.Next = reverseKGroup(nextNode, k)
    }

    return prev
}

