class Solution:
    def bottomView(self, root: Optional[TreeNode]) -> List[int]:
        if not root:
            return []

        # BFS with horizontal distance tracking
        # hd_map stores the last node seen at each horizontal distance
        hd_map = {}
        queue = deque()
        queue.append((root, 0))  # (node, horizontal_distance)

        while queue:
            node, hd = queue.popleft()
            # Overwrite with the latest node at this HD (bottom-most in BFS)
            hd_map[hd] = node.val

            if node.left is not None:
                queue.append((node.left, hd - 1))
            if node.right is not None:
                queue.append((node.right, hd + 1))

        # Sort by horizontal distance and return values
        result = [hd_map[hd] for hd in sorted(hd_map.keys())]
        return result

