class Solution {
    /**
     * @param {TreeNode|null} root
     * @return {number[]}
     */
    bottomView(root) {
        if (!root) return [];

        // BFS with horizontal distance tracking
        // hd_map stores the last node seen at each horizontal distance
        const hdMap = new Map();
        const queue = [[root, 0]]; // [node, horizontal_distance]

        while (queue.length > 0) {
            const [node, hd] = queue.shift();
            // Overwrite with the latest node at this HD (bottom-most in BFS)
            hdMap.set(hd, node.val);

            if (node.left !== null) {
                queue.push([node.left, hd - 1]);
            }
            if (node.right !== null) {
                queue.push([node.right, hd + 1]);
            }
        }

        // Sort by horizontal distance and return values
        const sortedKeys = Array.from(hdMap.keys()).sort((a, b) => a - b);
        return sortedKeys.map(k => hdMap.get(k));
    }
}

