class Solution {
    /**
     * @param {TreeNode|null} root
     * @return {number}
     */
    countNodes(root) {
        if (!root) return 0;

        // Compute left height (going all the way left)
        let leftHeight = 0;
        let node = root;
        while (node) {
            leftHeight++;
            node = node.left;
        }

        // Compute right height (going all the way right)
        let rightHeight = 0;
        node = root;
        while (node) {
            rightHeight++;
            node = node.right;
        }

        // If left and right heights are equal, it's a perfect binary tree
        if (leftHeight === rightHeight) {
            return (1 << leftHeight) - 1; // 2^h - 1
        }

        // Otherwise, recursively count left and right subtrees + 1 for root
        return 1 + this.countNodes(root.left) + this.countNodes(root.right);
    }
}

