 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */

class Solution {
    /**
     * @param {TreeNode} root
     * @return {number}
     */
    maxPathSum(root) {
        let res = root.val;  // Initialize result with root value

        const dfs = (node) => {
            if (!node) {
                return 0;
            }

            let maxL = Math.max(dfs(node.left), 0);  // Max path from left, ignore if negative
            let maxR = Math.max(dfs(node.right), 0);  // Max path from right, ignore if negative

            res = Math.max(res, node.val + maxL + maxR);  // Update global max with path through node

            return node.val + Math.max(maxL, maxR);  // Return max path including current node
        };

        dfs(root);
        return res;
    }
}

