     * @param {Node} node
     * @return {Node}
     */
    cloneGraph(node) {
        if (!node) {
            return null;
        }
        const q = [node];
        const mapping = new Map(); 
        mapping.set(node, new Node(node.val));
        while (q.length > 0) {
            const current = q.shift();
            for (const neighbor of current.neighbors) {
                if (!mapping.has(neighbor)) {
                    mapping.set(neighbor, new Node(neighbor.val));
                    q.push(neighbor); 
                }
                mapping.get(current).neighbors.push(mapping.get(neighbor));
            }
        }
        return mapping.get(node);
    }
}

