class Solution:
    def updateMatrix(self, mat: List[List[int]]) -> List[List[int]]:
        # Multi-source BFS from all 0-cells
        m, n = len(mat), len(mat[0])
        dist = [[0] * n for _ in range(m)]
        q = deque()

        # Initialize: enqueue all 0-cells, mark 1-cells with large distance
        for i in range(m):
            for j in range(n):
                if mat[i][j] == 0:
                    q.append((i, j))
                else:
                    dist[i][j] = float('inf')

        # BFS to find shortest distance to nearest 0
        directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]
        while q:
            r, c = q.popleft()
            for dr, dc in directions:
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n:
                    if dist[nr][nc] > dist[r][c] + 1:
                        dist[nr][nc] = dist[r][c] + 1
                        q.append((nr, nc))

        return dist

