func allPathsSourceTarget(graph [][]int) [][]int {
    // Result slice to store all paths from source (0) to target (n-1)
    var result [][]int
    n := len(graph)
    target := n - 1

    // Helper function for DFS traversal
    var dfs func(node int, path []int)
    dfs = func(node int, path []int) {
        // If we reached the target node, add current path to result
        if node == target {
            // Make a copy of the path to avoid reference issues
            pathCopy := make([]int, len(path))
            copy(pathCopy, path)
            result = append(result, pathCopy)
            return
        }

        // Explore all neighbors of current node
        for _, neighbor := range graph[node] {
            // Add neighbor to path and continue DFS
            dfs(neighbor, append(path, neighbor))
        }
    }

    // Start DFS from node 0 with initial path containing just node 0
    dfs(0, []int{0})

    return result
}

