class Solution {
    public boolean isBipartite(int[][] graph) {
        int n = graph.length;
        int[] colors = new int[n];  // 0: uncolored, 1: color A, -1: color B

        for (int i = 0; i < n; i++) {
            if (colors[i] == 0 \u0026\u0026 !dfs(i, 1, colors, graph)) {
                return false;
            }
        }

        return true;
    }

    private boolean dfs(int node, int color, int[] colors, int[][] graph) {
        colors[node] = color;

        for (int neighbor : graph[node]) {
            if (colors[neighbor] == 0) {
                if (!dfs(neighbor, -color, colors, graph)) {
                    return false;
                }
            } else if (colors[neighbor] == color) {
                return false;
            }
        }

        return true;
    }
}

