class Solution:
    def isBipartite(self, graph: List[List[int]]) -> bool:
        # Initialize variables
        n = len(graph)
        colors = [0] * n  # 0: uncolored, 1: color A, -1: color B

        def dfs(node: int, color: int) -> bool:
            # Color current node
            colors[node] = color

            # Check all neighbors
            for neighbor in graph[node]:
                # If neighbor uncolored, color it opposite
                if colors[neighbor] == 0:
                    if not dfs(neighbor, -color):
                        return False
                # If neighbor has same color as current node, graph is not bipartite
                elif colors[neighbor] == color:
                    return False
            return True

        # Try to color each uncolored node
        for i in range(n):
            if colors[i] == 0:
                if not dfs(i, 1):
                    return False

        return True

