class Solution:
    def lastStoneWeightII(self, stones: List[int]) -> int:
        # This problem reduces to partitioning stones into two groups
        # to minimize the absolute difference of their sums.
        # Equivalent to finding a subset with sum closest to totalSum / 2.
        total = sum(stones)
        target = total // 2

        # dp is a set of achievable subset sums
        dp = {0}

        for stone in stones:
            # Iterate in a new set to avoid using same stone twice
            new_dp = set()
            for s in dp:
                if s + stone <= target:
                    new_dp.add(s + stone)
            dp |= new_dp

        # The best subset sum closest to target
        best = max(dp)

        # The answer is the difference between the two groups
        return total - 2 * best

