func lastStoneWeightII(stones []int) int {
    // This problem reduces to partitioning stones into two groups
    // to minimize the absolute difference of their sums.
    // Equivalent to finding a subset with sum closest to totalSum / 2.
    total := 0
    for _, s := range stones {
        total += s
    }
    target := total / 2

    // dp[i] = true means sum i is achievable
    dp := make([]bool, target+1)
    dp[0] = true

    for _, stone := range stones {
        // Iterate backwards to avoid using the same stone twice
        for j := target; j >= stone; j-- {
            if dp[j-stone] {
                dp[j] = true
            }
        }
    }

    // Find the best achievable sum closest to target
    best := 0
    for j := target; j >= 0; j-- {
        if dp[j] {
            best = j
            break
        }
    }

    // The answer is the difference between the two groups
    return total - 2*best
}

