func lengthOfLIS(nums []int) int {
   // dp[i] represents length of longest increasing subsequence ending at index i
   n := len(nums)
   dp := make([]int, n)
   // Initialize - single number is a subsequence of length 1
   for i := 0; i < n; i++ {
       dp[i] = 1
   }

   // For each position, look at all previous numbers
   for i := 1; i < n; i++ {
       for j := 0; j < i; j++ {
           // If current number is greater, we can add it to subsequence ending at j
           if nums[i] > nums[j] {
               dp[i] = int(math.Max(float64(dp[i]), float64(dp[j]+1)))
           }
       }
   }

   // Find the longest subsequence from all positions
   maxLen := 0
   for _, length := range dp {
       maxLen = int(math.Max(float64(maxLen), float64(length)))
   }

   return maxLen
}

