class Solution {
public:
    int lengthOfLIS(vector<int>\u0026 nums) {
        if (nums.empty()) return 0;

        // Binary search approach with patience sorting
        vector<int> tails;

        for (int num : nums) {
            // Find position to insert/replace using binary search
            auto it = lower_bound(tails.begin(), tails.end(), num);

            if (it == tails.end()) {
                tails.push_back(num);
            } else {
                *it = num;
            }
        }

        return tails.size();
    }
};

