   public int numDecodings(String s) {
       if (s == null || s.length() == 0 || s.charAt(0) == '0') {
           return 0;
       }

       int n = s.length();
       int[] dp = new int[n + 1];
       dp[0] = 1;  // Empty string has 1 way to decode
       dp[1] = 1;  // First digit has 1 way if not '0'

       for (int i = 2; i <= n; i++) {
           // Check if single digit is valid
           if (s.charAt(i - 1) != '0') {
               dp[i] += dp[i - 1];
           }

           // Check if two digit number is valid (10-26)
           int twoDigit = Integer.parseInt(s.substring(i - 2, i));
           if (twoDigit >= 10 \u0026\u0026 twoDigit <= 26) {
               dp[i] += dp[i - 2];
           }
       }

       return dp[n];
   }
}

