    def wordBreak(self, s: str, wordDict: List[str]) -> bool:
        # Initialize dp array with length + 1 for empty string case
        dp = [False] * (len(s) + 1)
        # Empty string is always breakable
        dp[len(s)] = True

        # Start from end of string
        for i in range(len(s) - 1, -1, -1):
            # Try each word in dictionary
            for w in wordDict:
                # Check if word fits and matches
                if (i + len(w)) <= len(s) and s[i : i + len(w)] == w:
                    # If word matches, state depends on remaining substring
                    dp[i] = dp[i + len(w)]
                # Early exit if we found a valid break
                if dp[i]:
                    break

        return dp[0]

