    public boolean wordBreak(String s, List<String> wordDict) {
        // Create dp array with additional slot for empty string
        boolean[] dp = new boolean[s.length() + 1];
        // Empty string is always breakable
        dp[s.length()] = true;

        // Process string from right to left
        for (int i = s.length() - 1; i >= 0; i--) {
            // Try each word in dictionary
            for (String w : wordDict) {
                // Check if word fits and matches current position
                if ((i + w.length()) <= s.length() \u0026\u0026 
                     s.substring(i, i + w.length()).equals(w)) {
                    dp[i] = dp[i + w.length()];
                }
                // Early exit if we found a valid break
                if (dp[i]) {
                    break;
                }
            }
        }

        return dp[0];
    }
