public:
    bool wordBreak(string s, vector<string>\u0026 wordDict) {
        // Create a set for O(1) lookup of dictionary words
        unordered_set<string> dict(wordDict.begin(), wordDict.end());

        // dp[i] represents whether s[0...i] can be segmented into dictionary words
        vector<bool> dp(s.length() + 1, false);
        dp[0] = true;  // Empty string is always valid

        // For each position i in string s
        for (int i = 1; i <= s.length(); i++) {
            // Try all possible substrings ending at i
            for (int j = 0; j < i; j++) {
                // If s[0...j] is valid and s[j...i] is in dictionary
                if (dp[j] \u0026\u0026 dict.find(s.substr(j, i-j)) != dict.end()) {
                    dp[i] = true;
                    break;
                }
            }
        }

        return dp[s.length()];
    }
};

