     */
    longestCommonSubsequence(text1, text2) {
        // Initialize dp matrix with extra row/column for empty string
        const dp = Array(text1.length + 1)
            .fill()
            .map(() => Array(text2.length + 1).fill(0));

        // Process from bottom-right to top-left
        for (let i = text1.length - 1; i >= 0; i--) {
            for (let j = text2.length - 1; j >= 0; j--) {
                // If characters match, add 1 to diagonal
                if (text1[i] === text2[j]) {
                    dp[i][j] = 1 + dp[i + 1][j + 1];
                // If no match, take maximum of adjacent cells
                } else {
                    dp[i][j] = Math.max(dp[i][j + 1], dp[i + 1][j]);
                }
            }
        }

        return dp[0][0];
    }
}

