class Solution:
    def numDistinct(self, s: str, t: str) -> int:
        m, n = len(s), len(t)

        # dp[j] represents the number of distinct subsequences of s[0..i-1] that equal t[0..j-1]
        # Space-optimized 1D DP
        dp = [0] * (n + 1)
        dp[0] = 1  # Empty t is a subsequence of any prefix of s

        for i in range(1, m + 1):
            # Iterate in reverse to avoid overwriting values we still need
            for j in range(min(i, n), 0, -1):
                if s[i - 1] == t[j - 1]:
                    # Match: use this char (dp[j-1]) + skip this char (dp[j])
                    dp[j] += dp[j - 1]
                # If no match, dp[j] stays the same (skip s[i-1])

        return dp[n]

