func countSubstrings(s string) int {
    n := len(s)
    // dp[i][j] will be true if the string from index i to j is a palindrome
    dp := make([][]bool, n)
    for k := range dp {
        dp[k] = make([]bool, n)
    }

    count := 0

    // Iterate backwards for 'i' to ensure row 'i+1' is computed before row 'i'
    for i := n - 1; i >= 0; i-- {
        for j := i; j < n; j++ {
            // Check if characters at boundaries match
            if s[i] == s[j] {
                // Two cases result in a palindrome here:
                // 1. j - i < 2: The substring is length 1 (i==j) or 2 (adjacent characters)
                // 2. dp[i+1][j-1] is true: The inner substring is already a valid palindrome
                if j - i < 2 || dp[i+1][j-1] {
                    dp[i][j] = true
                    count++
                }
            }
        }
    }
    return count
}

