    bool canJump(vector<int>\u0026 nums) {
        // Track the farthest reachable position
        int maxReach = 0;

        for (int i = 0; i < nums.size(); i++) {
            // If current position is unreachable, return false
            if (i > maxReach) {
                return false;
            }

            // Update the farthest reachable position
            maxReach = max(maxReach, i + nums[i]);

            // If we can reach or pass the last index, return true
            if (maxReach >= nums.size() - 1) {
                return true;
            }
        }

        return true;
    }
};

