func jump(nums []int) int {
    // Edge case: if array length is 1, no jumps needed
    if len(nums) <= 1 {
        return 0
    }

    // Initialize variables to track current position and jumps
    curMax := 0    // tracks the farthest position we can reach from current position
    nextMax := 0   // tracks the farthest we can reach in the next jump
    jumps := 0     // counts number of jumps needed

    // Iterate through array (except last element as we don't need to jump from there)
    for i := 0; i < len(nums)-1; i++ {
        // Update the farthest position we can reach
        nextMax = max(nextMax, i + nums[i])

        // If we've reached the current maximum position
        // we need to make a jump
        if i == curMax {
            jumps++
            curMax = nextMax

            // If we can already reach the end, break
            if curMax >= len(nums)-1 {
                break
            }
        }
    }

    return jumps
}

