    def maxA(self, n: int) -> int:
        # dp[i] = maximum number of A's printable with i key presses
        dp = [0] * (n + 1)

        for i in range(1, n + 1):
            # Option 1: just press 'A' one more time
            dp[i] = dp[i - 1] + 1

            # Option 2: at some step j, we did Ctrl-A + Ctrl-C,
