class Solution {
    /**
     * @param {number[]} nums
     * @return {number}
     */
    maxCoins(nums) {
        // Pad the array with 1s on both ends
        nums = [1, ...nums, 1];
        const n = nums.length;

        // dp[i][j] = max coins from bursting all balloons between i and j (exclusive)
        const dp = Array.from({ length: n }, () => new Array(n).fill(0));

        // Iterate over interval lengths
        for (let length = 2; length < n; length++) {
            for (let i = 0; i <= n - length - 1; i++) {
                const j = i + length;
                // Try each balloon k as the last one to burst in interval (i, j)
                for (let k = i + 1; k < j; k++) {
                    const coins = nums[i] * nums[k] * nums[j];
                    dp[i][j] = Math.max(dp[i][j], dp[i][k] + coins + dp[k][j]);
                }
            }
        }

        return dp[0][n - 1];
    }
}

