class Solution:
    def canCross(self, stones: List[int]) -> bool:
        # Map each stone position to the set of jump sizes that can reach it
        stone_map = {s: set() for s in stones}
        stone_map[0].add(0)

        for stone in stones:
            for k in stone_map[stone]:
                # Try jumps of k-1, k, k+1
                for jump in (k - 1, k, k + 1):
                    if jump > 0 and (stone + jump) in stone_map:
                        stone_map[stone + jump].add(jump)

        # Check if the last stone is reachable
        return len(stone_map[stones[-1]]) > 0

