                for (long long jump : {k - 1, k, k + 1}) {
                    if (jump > 0 \u0026\u0026 stone_map.count(stone + jump)) {
                        stone_map[stone + jump].insert(jump);
                    }
                }
            }
        }

        // Check if the last stone is reachable
        return !stone_map[(long long)stones.back()].empty();
    }
};

