class Solution {
    /**
     * @param {number} n
     * @return {number}
     */
    countOrders(n) {
        const MOD = 1000000007n;
        let result = 1n;
        // For each order i, the number of ways to insert (Pi, Di)
        // into the existing sequence is (2i - 1) * i
        for (let i = 1; i <= n; i++) {
            const bi = BigInt(i);
            result = result * (2n * bi - 1n) % MOD * bi % MOD;
        }
        return Number(result);
    }
}

