func numberOfArithmeticSlices(nums []int) int {
    n := len(nums)
    // dp[i] maps difference d -> count of arithmetic subsequences
    // of length >= 2 ending at index i with common difference d
    dp := make([]map[int64]int, n)
    for i := 0; i < n; i++ {
        dp[i] = make(map[int64]int)
    }
    result := 0

    for i := 0; i < n; i++ {
        for j := 0; j < i; j++ {
            d := int64(nums[i]) - int64(nums[j])
            // Number of weak subsequences (len >= 2) ending at j with diff d
            countAtJ := dp[j][d]
            // These countAtJ subsequences, when extended by nums[i],
            // become length >= 3, so they are valid arithmetic subsequences
            result += countAtJ
            // Update dp[i][d]: +1 for the new pair (j, i), +countAtJ for extensions
            dp[i][d] += countAtJ + 1
        }
    }

    return result
}

