class Solution {
    public int leastInterval(char[] tasks, int n) {
        // Count frequency of each task
        int[] taskCount = new int[26];
        for (char task : tasks) {
            taskCount[task - 'A']++;
        }

        // Find maximum frequency
        int maxFreq = 0;
        for (int count : taskCount) {
            maxFreq = Math.max(maxFreq, count);
        }

        // Count how many tasks have the maximum frequency
        int maxFreqTasks = 0;
        for (int count : taskCount) {
            if (count == maxFreq) {
                maxFreqTasks++;
            }
        }

        // Calculate minimum intervals needed
        // Formula: (maxFreq - 1) * (n + 1) + maxFreqTasks
        int minIntervals = (maxFreq - 1) * (n + 1) + maxFreqTasks;

        // Return the maximum between calculated intervals and total tasks
        return Math.max(minIntervals, tasks.length);
    }
}

