    minMeetingRooms(intervals) {
        // Extract and sort start and end times
        const start = intervals.map(i => i.start).sort((a, b) => a - b);
        const end = intervals.map(i => i.end).sort((a, b) => a - b);

        let res = 0, count = 0, s = 0, e = 0;
        while (s < intervals.length) {
            if (start[s] < end[e]) {
                s++;
                count++;  // New meeting starts
            } else {
                e++;
                count--;  // Meeting ends
            }
            res = Math.max(res, count);  // Track max rooms needed
        }
        return res;
    }
}

