class Solution:
    def kthSmallest(self, matrix: List[List[int]], k: int) -> int:
        n = len(matrix)

        def count_less_equal(mid: int) -> int:
            # Start from bottom-left corner
            count = 0
            row = n - 1
            col = 0
            while row >= 0 and col < n:
                if matrix[row][col] <= mid:
                    # All elements in this column from row 0 to current row are <= mid
                    count += row + 1
                    col += 1
                else:
                    row -= 1
            return count

        # Binary search on value range
        lo = matrix[0][0]
        hi = matrix[n - 1][n - 1]

        while lo < hi:
            mid = lo + (hi - lo) // 2
            if count_less_equal(mid) < k:
                lo = mid + 1
            else:
                hi = mid

        return lo

