class Solution:
    def canCompleteCircuit(self, gas: List[int], cost: List[int]) -> int:
        # If total gas < total cost, impossible to complete the circuit
        if sum(gas) < sum(cost):
            return -1

        # Greedy: track current tank and starting index
        tank = 0
        start = 0

        for i in range(len(gas)):
            tank += gas[i] - cost[i]
            # If tank goes negative, we can't start from 'start' or any station
            # between 'start' and 'i', so reset to i + 1
            if tank < 0:
                start = i + 1
                tank = 0

        return start

