    candy(ratings) {
        const n = ratings.length;
        // Initialize every child with 1 candy
        const candies = new Array(n).fill(1);

        // Left to right pass: ensure right neighbor with higher rating gets more
        for (let i = 1; i < n; i++) {
            if (ratings[i] > ratings[i - 1]) {
                candies[i] = candies[i - 1] + 1;
            }
        }

        // Right to left pass: ensure left neighbor with higher rating gets more
        for (let i = n - 2; i >= 0; i--) {
            if (ratings[i] > ratings[i + 1]) {
                candies[i] = Math.max(candies[i], candies[i + 1] + 1);
            }
        }

        // Return the total number of candies
        return candies.reduce((sum, val) => sum + val, 0);
    }
}

