public:
    uint32_t reverseBits(uint32_t n) {
        uint32_t result = 0;

        // Process each of the 32 bits
        for (int i = 0; i < 32; i++) {
            // Shift result left to make room for next bit
            result <<= 1;

            // Extract rightmost bit from n and add to result
            result |= (n \u0026 1);

            // Shift n right to process next bit
            n >>= 1;
        }

        return result;
    }
};

