func addBinary(a string, b string) string {
    // Initialize result slice and variables
    var result []byte
    carry := 0
    i, j := len(a)-1, len(b)-1

    // Process digits from right to left
    for i >= 0 || j >= 0 || carry > 0 {
        // Get digits, use 0 if we've run out of digits
        digitA := 0
        if i >= 0 {
            digitA = int(a[i] - '0')
        }

        digitB := 0
        if j >= 0 {
            digitB = int(b[j] - '0')
        }

        // Calculate current sum and carry
        currentSum := digitA + digitB + carry
        carry = currentSum / 2
        currentDigit := currentSum % 2

        // Add current digit to result
        result = append([]byte{byte(currentDigit + '0')}, result...)

        i--
        j--
    }

    return string(result)
}

