class Solution {
    /**
     * @param {number[]} nums
     * @return {number}
     */
    singleNumber(nums) {
        // ones: bits that have appeared 1 mod 3 times
        // twos: bits that have appeared 2 mod 3 times
        let ones = 0;
        let twos = 0;

        for (const num of nums) {
            // 'ones' is updated with bits from num, but only if
            // those bits are not already in 'twos'
            ones = (ones ^ num) \u0026 ~twos;
            // 'twos' is updated with bits from num, but only if
            // those bits are not already in 'ones'
            twos = (twos ^ num) \u0026 ~ones;
        }

        // After processing all numbers, 'ones' holds the single number
        return ones;
    }
}

