func getSum(a int, b int) int {
    mask := 0xFFFFFFFF
    for b != 0 {
        // Calculate carry and mask to 32 bits
        carry := (a \u0026 b) \u0026 mask
        // Sum without carry
        a = (a ^ b) \u0026 mask
        b = (carry << 1) \u0026 mask
    }
    // Handle negative numbers
    if a\u00260x80000000 != 0 {
        return -((^a \u0026 mask) + 1)
    }
    return a
