func divide(dividend int, divisor int) int {
    // Define maximum and minimum integer constants
    const MaxInt = 1<<31 - 1
    const MinInt = -1 << 31

    // Handle special cases
    if dividend == MinInt \u0026\u0026 divisor == -1 {
        return MaxInt
    }
    if divisor == 1 {
        return dividend
    }
    if divisor == -1 {
        return -dividend
    }

    // Determine sign of result
    sign := 1
    if (dividend < 0) != (divisor < 0) {
        sign = -1
    }

    // Convert to positive numbers
    dvd := abs(dividend)
    dvs := abs(divisor)

    // Perform division using bit manipulation
    quotient := 0
    for dvd >= dvs {
        temp := dvs
        multiple := 1
        for dvd >= (temp << 1) {
            temp <<= 1
            multiple <<= 1
        }
        dvd -= temp
        quotient += multiple
    }

    return sign * quotient
}

// Helper function to calculate absolute value
func abs(x int) int {
    if x < 0 {
        return -x
    }
    return x
}

