class Solution {
    /**
     * @param {number[][]} image
     * @param {number} sr
     * @param {number} sc
     * @param {number} color
     * @return {number[][]}
     */
    floodFill(image, sr, sc, color) {
        const R = image.length;
        const C = image[0].length;
        const oldColor = image[sr][sc];

        // Skip if new color is same as old
        if (oldColor === color) {
            return image;
        }

        const dfs = (r, c) => {
            // Check bounds and color match
            if (r < 0 || r >= R || c < 0 || c >= C || image[r][c] !== oldColor) {
                return;
            }

            // Update color and explore neighbors
            image[r][c] = color;
            dfs(r - 1, c);
            dfs(r + 1, c);
            dfs(r, c - 1);
            dfs(r, c + 1);
        };

        dfs(sr, sc);
        return image;
    }
}

