class Solution {
    public int[][] floodFill(int[][] image, int sr, int sc, int color) {
        int R = image.length;
        int C = image[0].length;
        int oldColor = image[sr][sc];

        // Skip if colors match
        if (oldColor == color) {
            return image;
        }

        dfs(image, sr, sc, R, C, oldColor, color);
        return image;
    }

    private void dfs(int[][] image, int r, int c, int R, int C, int oldColor, int newColor) {
        // Check bounds and color match
        if (r < 0 || r >= R || c < 0 || c >= C || image[r][c] != oldColor) {
            return;
        }

        // Update color and explore neighbors
        image[r][c] = newColor;
        dfs(image, r - 1, c, R, C, oldColor, newColor);
        dfs(image, r + 1, c, R, C, oldColor, newColor);
        dfs(image, r, c - 1, R, C, oldColor, newColor);
        dfs(image, r, c + 1, R, C, oldColor, newColor);
    }
}

