func floodFill(image [][]int, sr int, sc int, color int) [][]int {
    R, C := len(image), len(image[0])
    oldColor := image[sr][sc]

    // No need to perform flood fill if the colors are the same
    if oldColor == color {
        return image
    }

    var dfs func(r, c int)
    dfs = func(r, c int) {
        // Check if pixel is within bounds and has the old color
        if r < 0 || r >= R || c < 0 || c >= C || image[r][c] != oldColor {
            return
        }
        // Update the color and explore neighbors
        image[r][c] = color
        dfs(r-1, c) // Up
        dfs(r+1, c) // Down
        dfs(r, c-1) // Left
        dfs(r, c+1) // Right
    }

    dfs(sr, sc)
    return image
}

