                    // Check and subtract shared edges with neighbors
                    if (r > 0 \u0026\u0026 grid[r - 1][c] == 1) {
                        perimeter -= 2;
                    }
                    if (c > 0 \u0026\u0026 grid[r][c - 1] == 1) {
                        perimeter -= 2;
                    }
                }
            }
        }

        return perimeter;
    }
}

