class Solution:
    def findDiagonalOrder(self, mat: List[List[int]]) -> List[int]:
        if not mat or not mat[0]:
            return []

        m, n = len(mat), len(mat[0])
        result = []

        # There are m + n - 1 diagonals
        for d in range(m + n - 1):
            # Collect elements on this diagonal
            diagonal = []
            # Row ranges from max(0, d - n + 1) to min(d, m - 1)
            r_start = max(0, d - n + 1)
            r_end = min(d, m - 1)
            for r in range(r_start, r_end + 1):
                diagonal.append(mat[r][d - r])

            # Even diagonals go upward (bottom-left to top-right)
            # so we reverse the collected order
            if d % 2 == 0:
                result.extend(diagonal[::-1])
            else:
                result.extend(diagonal)

        return result

