            const rStart = Math.max(0, d - n + 1);
            const rEnd = Math.min(d, m - 1);
            for (let r = rStart; r <= rEnd; r++) {
                diagonal.push(mat[r][d - r]);
            }

            // Even diagonals go upward (reverse the collected order)
            if (d % 2 === 0) {
                diagonal.reverse();
            }

            for (const val of diagonal) {
                result.push(val);
            }
        }

        return result;
    }
