func findDiagonalOrder(mat [][]int) []int {
    if len(mat) == 0 || len(mat[0]) == 0 {
        return []int{}
    }

    m := len(mat)
    n := len(mat[0])
    result := make([]int, 0, m*n)

    // There are m + n - 1 diagonals
    for d := 0; d < m+n-1; d++ {
        // Collect elements on this diagonal
        diagonal := []int{}
        // Row ranges from max(0, d-n+1) to min(d, m-1)
        rStart := d - n + 1
        if rStart < 0 {
            rStart = 0
        }
        rEnd := d
        if rEnd > m-1 {
            rEnd = m - 1
        }
        for r := rStart; r <= rEnd; r++ {
            diagonal = append(diagonal, mat[r][d-r])
        }

        // Even diagonals go upward, so reverse
        if d%2 == 0 {
            for i, j := 0, len(diagonal)-1; i < j; i, j = i+1, j-1 {
                diagonal[i], diagonal[j] = diagonal[j], diagonal[i]
            }
        }
        result = append(result, diagonal...)
    }

    return result
}

