class Solution:
    def diagonalSort(self, mat: List[List[int]]) -> List[List[int]]:
        rows, cols = len(mat), len(mat[0])
        diagonal_dict = {}

        # Map each element to its corresponding diagonal in the hash table
        for r in range(rows):
            for c in range(cols):
                if r - c not in diagonal_dict:
                    diagonal_dict[r - c] = []
                diagonal_dict[r - c].append(mat[r][c])

        # Sort the elements within each diagonal
        for key in diagonal_dict:
            diagonal_dict[key].sort()

        # Update the matrix with the sorted values
        for r in range(rows):
            for c in range(cols):
                mat[r][c] = diagonal_dict[r - c].pop(0)

        return mat

