    for r := 0; r < m; r++ {
        for c := 0; c < n; c++ {
            key := r - c
            diagonalDict[key] = append(diagonalDict[key], mat[r][c])
        }
    }

    // Sort the elements within each diagonal
    for _, diagonal := range diagonalDict {
        sort.Ints(diagonal)
    }

    // Update the matrix with the sorted values
    for r := 0; r < m; r++ {
        for c := 0; c < n; c++ {
            key := r - c
            mat[r][c] = diagonalDict[key][0]
            diagonalDict[key] = diagonalDict[key][1:]
        }
    }

    return mat
}

