class Solution:
    def minTotalDistance(self, grid: List[List[int]]) -> int:
        # Collect all row and column indices of homes
        rows = []
        cols = []
        for i in range(len(grid)):
            for j in range(len(grid[0])):
                if grid[i][j] == 1:
                    rows.append(i)
        # Collect columns sorted by column index
        for j in range(len(grid[0])):
            for i in range(len(grid)):
                if grid[i][j] == 1:
                    cols.append(j)

        # Find median and compute total distance
        def min_distance_1d(points: List[int]) -> int:
            # Points are already sorted
            median = points[len(points) // 2]
            return sum(abs(p - median) for p in points)

        return min_distance_1d(rows) + min_distance_1d(cols)

