class MovingAverage {
  /**
   * @param {number} size - The window size for the moving average
   */
  constructor(size) {
    // Window size for the moving average
    this.size = size;
    // Array used as a queue to store the current window of values
    this.window = [];
    // Running sum of elements in the window
    this.windowSum = 0.0;
  }

  /**
   * Add a new integer val to the stream and return the moving average
   * of the last size values.
   * @param {number} val
   * @return {number}
   */
  next(val) {
    // Add the new value to the window
    this.window.push(val);
    this.windowSum += val;

    // If window exceeds the allowed size, remove the oldest element
    if (this.window.length > this.size) {
      this.windowSum -= this.window.shift();
    }

    // Return the current moving average
    return this.windowSum / this.window.length;
  }
}

