class MovingAverage {
    private int size;
    private java.util.LinkedList<Integer> window;
    private double windowSum;

    public MovingAverage(int size) {
        this.size = size;
        this.window = new java.util.LinkedList<>();
        this.windowSum = 0.0;
    }

    public double next(int val) {
        // Add the new value to the window
        window.addLast(val);
        windowSum += val;

