class MyCircularQueue {
private:
    vector<int> queue;
    int capacity;
    int size;
    int frontIdx;

public:
    MyCircularQueue(int k) {
        queue.resize(k, 0);
        capacity = k;
        size = 0;
        frontIdx = 0;
    }

    bool enQueue(int value) {
        if (isFull()) return false;
        int idx = (frontIdx + size) % capacity;
        queue[idx] = value;
        size++;
        return true;
    }

    bool deQueue() {
        if (isEmpty()) return false;
        frontIdx = (frontIdx + 1) % capacity;
        size--;
        return true;
    }

    int Front() {
        if (isEmpty()) return -1;
        return queue[frontIdx];
    }

    int Rear() {
        if (isEmpty()) return -1;
        int idx = (frontIdx + size - 1) % capacity;
        return queue[idx];
    }

    bool isEmpty() {
        return size == 0;
    }

    bool isFull() {
        return size == capacity;
    }
};

